#[test]
fn keeps_inventory_notes_in_normalized_order() {
    let notes = vec![
        "  URGENT restock batteries ".to_owned(),
        "".to_owned(),
        "general reminder".to_owned(),
        "low STOCK on cables".to_owned(),
    ];

    assert_eq!(
        reorder_notes(&notes),
        vec![
            "urgent restock batteries".to_owned(),
            "low stock on cables".to_owned(),
        ]
    );
}

hints.solutionCode:
pub fn reorder_notes(notes: &[String]) -> Vec<String> {
    let mut relevant_notes = Vec::new();

    for note in notes {
        let normalized = note.trim().to_lowercase();
        if normalized.is_empty() {
            continue;
        }

        let is_inventory_note =
            normalized.contains("urgent") || normalized.contains("stock");
        if is_inventory_note {
            relevant_notes.push(normalized);
        }
    }

    relevant_notes
}

